import 'whatwg-fetch';

const key = 'light_mode'
const toggle = document.querySelector('#light') as HTMLInputElement;
const imageProfile = document.getElementById('profile') as HTMLImageElement;

async function loadProfileFromGithub() {
    const response = await fetch('https://api.github.com/users/seanghay');
    const data = await response.json();
    const { avatar_url: imageUrl } = data;    
    imageProfile.src = imageUrl;
}

async function chrismas() {
    const currentDate = new Date();
    if ((currentDate.getDate() !== 24 && 
        currentDate.getDate() !== 25) 
        || currentDate.getMonth() !== 11) {
        return;
    }

    const hat = document.querySelector('#hat') as HTMLImageElement;

    if (hat) {
        hat.hidden = false;
    }
}


const localState = localStorage.getItem(key);

function darkModeOn(on) {
    if (on) {
        document.documentElement.classList.remove('light');
    } else {
        document.documentElement.classList.add('light');
    }
}

window.addEventListener('DOMContentLoaded', async(e) => {
    await loadProfileFromGithub();
    await chrismas();
});

const isDark = window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches

toggle.checked = isDark;

darkModeOn(isDark);

window.matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
    toggle.checked = e.matches;
    darkModeOn(e.matches);
});

toggle.addEventListener('change', () => {
    darkModeOn(toggle.checked);
    localStorage.setItem(key, toggle.checked.toString());
})